  "projects.sync.aheadTitle": { uk: "Дев-репо попереду клієнтського на {n} комітів — ще не доставлено клієнту", ru: "Дев-репо впереди клиентского на {n} коммитов — ещё не доставлено клиенту", en: "Dev repo is {n} commits ahead of client — not delivered yet" },
