  "projects.spec": { uk: "Спека проєкту", ru: "Спека проекта", en: "Project spec" },
  "projects.specHint": { uk: "Повна спека/роадмеп — загальний контекст. Claude розробника читає її через dev-API перед роботою (менше зайвих питань).", ru: "Полная спека/роадмап — общий контекст. Claude разработчика читает её через dev-API перед работой (меньше лишних вопросов).", en: "Full spec/roadmap — shared context. The developer's Claude reads it via dev-API before working (fewer questions)." },
  "projects.devInfo": { uk: "Інфо для розробника (внутр.)", ru: "Инфо для разработчика (внутр.)", en: "Info for developer (internal)" },
  "projects.devInfoHint": { uk: "Те, що ви взяли у клієнта і треба передати розробнику — він бачить це в картці проєкту та через dev-API. Клієнт НЕ бачить.", ru: "То, что вы взяли у клиента и нужно передать разработчику — он видит это в карточке проекта и через dev-API. Клиент НЕ видит.", en: "Info you took from the client to pass to the developer — visible in the project card and via dev-API. Client does NOT see it." },
  "projects.autoApprove": { uk: "Довірений розробник — без мого апрува", ru: "Доверенный разработчик — без моего апрува", en: "Trusted developer — no approval needed" },
  "projects.autoApproveHint": { uk: "Клієнт-видимі коментарі розробника публікуються одразу (без модерації), а готові задачі (Review) закриваються одразу — без мого підтвердження. Вмикайте для досвідчених розробників.", ru: "Клиент-видимые комментарии разработчика публикуются сразу (без модерации), а готовые задачи (Review) закрываются сразу — без моего подтверждения. Включайте для опытных разработчиков.", en: "The developer's client-facing comments publish immediately (no moderation), and finished tasks (Review) close immediately — without my approval. Enable for experienced developers." },
  "projects.gitflowDelivery": { uk: "Gitflow-доставка (feature-гілка → PR у develop)", ru: "Gitflow-доставка (feature-ветка → PR в develop)", en: "Gitflow delivery (feature branch → PR to develop)" },
  "projects.gitflowDeliveryHint": { uk: "Портал пушить feature-гілку розробника в клієнтський репо і відкриває PR у develop (замість squash-знімка). Розробник працює per-task на гілці від client-sync/develop. Взаємовиключно з «Автодоставкою».", ru: "Портал пушит feature-ветку разработчика в клиентский репо и открывает PR в develop (вместо squash-снимка). Разработчик работает per-task на ветке от client-sync/develop. Взаимоисключающе с «Автодоставкой».", en: "Portal pushes the developer's feature branch to the client repo and opens a PR to develop (instead of a squash snapshot). Mutually exclusive with auto-delivery." },
  "projects.deliverBranch": { uk: "Цільова гілка доставки", ru: "Целевая ветка доставки", en: "Delivery target branch" },
  "projects.deliverBranchHint": { uk: "Куди доставляти наш код у клієнтський репо (по всіх репо проєкту). Порожньо = дефолтна гілка клієнта. Для gitflow вкажіть develop.", ru: "Куда доставлять наш код в клиентский репо (по всем репо проекта). Пусто = дефолтная ветка клиента. Для gitflow укажите develop.", en: "Where to deliver our code in the client repo (across all project repos). Empty = client default branch. For gitflow set develop." },
  "flow.deliver": { uk: "доставка", ru: "доставка", en: "delivery" },
  "flow.sync": { uk: "синк", ru: "синк", en: "sync" },
