  "projects.vercel": { uk: "Деплой клієнта — Vercel", ru: "Деплой клиента — Vercel", en: "Client deploy — Vercel" },
  "projects.vercelHint": { uk: "Vercel сам деплоїть при пуші — апрув не потрібен; портал лише моніторить статус після доставки. Токен + Project ID (+ Team ID, якщо під командою).", ru: "Vercel деплоит сам при пуше — апрув не нужен; портал лишь мониторит статус после доставки. Токен + Project ID (+ Team ID, если под командой).", en: "Vercel deploys automatically on push — no approval; portal only monitors status after delivery. Token + Project ID (+ Team ID if under a team)." },
