  "deliver.schemaAutoDetected": { uk: "Міграція накотиться сама при деплої клієнта — підтвердження не потрібне. Виявлено в коді → {mech}", ru: "Миграция накатится сама при деплое клиента — подтверждение не нужно. Обнаружено в коде → {mech}", en: "Migration runs automatically on the client deploy — no confirmation needed. Detected in code → {mech}" },
