  "deliver.chk.ready": { uk: "Все налаштовано — автодоставка спрацює.", ru: "Всё настроено — автодоставка сработает.", en: "All set — auto-delivery will run." },
  "deliver.chk.title": { uk: "Для автодоставки бракує налаштувань:", ru: "Для автодоставки не хватает настроек:", en: "Auto-delivery is missing settings:" },
  "deliver.chk.noPairs": { uk: "не задані репозиторії dev→client (devGit/clientGit) — доставляти нічого.", ru: "не заданы репозитории dev→client (devGit/clientGit) — доставлять нечего.", en: "dev→client repos not set (devGit/clientGit) — nothing to deliver." },
  "deliver.chk.gitflowConflict": { uk: "увімкнено gitflow-режим — він має пріоритет, squash-автодоставка не спрацює. Залиш щось одне.", ru: "включён gitflow-режим — он имеет приоритет, squash-автодоставка не сработает. Оставь что-то одно.", en: "gitflow mode is on — it takes priority, squash auto-delivery won't run. Keep only one." },
  "deliver.chk.noAutoApprove": { uk: "вимкнено autoApprove — автодоставка піде лише для задач з autoDone; звичайні задачі підуть на ручну приймачу й самі не доставляться.", ru: "выключен autoApprove — автодоставка пойдёт только для задач с autoDone; обычные задачи уйдут на ручную приёмку и сами не доставятся.", en: "autoApprove is off — auto-delivery fires only for autoDone tasks; regular tasks go to manual review and won't auto-deliver." },
  "deliver.chk.directNoDeploy": { uk: "прямий режим (squash у main) без деплой-кредів — автодоставка не запуститься. Додай Railway/Vercel у налаштуваннях деплою або увімкни PR-режим (clientDeliverPR).", ru: "прямой режим (squash в main) без деплой-кредов — автодоставка не запустится. Добавь Railway/Vercel в настройках деплоя или включи PR-режим (clientDeliverPR).", en: "direct mode (squash to main) without deploy creds — auto-delivery won't start. Add Railway/Vercel in deploy settings or enable PR mode (clientDeliverPR)." },
  "deliver.chk.railwayIncomplete": { uk: "Railway: задано токен, але бракує {fields} — код доставиться в main, але деплой не буде авто-схвалено (зависне в NEEDS_APPROVAL).", ru: "Railway: задан токен, но не хватает {fields} — код доставится в main, но деплой не будет авто-апрувнут (повиснет в NEEDS_APPROVAL).", en: "Railway: token set but {fields} missing — code will reach main, but the deploy won't be auto-approved (stuck at NEEDS_APPROVAL)." },

